namespace test_reaction {

std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    Var<int> a(initialA);
    Var<int> b(initialB);
    Var<int> recomputeCount(0);

    CalcExpr<int> sumCalc([this](const NodePtr& node) {
        return a.get() + b.get();
    });
    sumCalc.addObCb([this](const NodePtr& node, const void* oldValue, const void* newValue) {
        recomputeCount.set(recomputeCount.get() + 1);
    });

    // Non-batch updates
    {
        a.set(nonBatchA);
        b.set(nonBatchB);
        int nonBatchCount = recomputeCount.get();

        // Batch context
        {
            Batch batch([this](const NodePtr& node) {
                a.set(batchA);
                b.set(batchB);
            });
            batch.execute();
            int batchCount = recomputeCount.get();

            return std::make_tuple(sumCalc.get(), nonBatchCount, batchCount);
        }
    }
}

