        .hitRatio = statsAfterInvalidate.hitRatio,
        .metricsCachedExists = metricsAfterCache && metricsAfterCache->exists,
        .metricsClearedAfterInvalidate = metricsAfterInvalidate == nullptr && metricsBefore == nullptr,
    };
}

