inline GenericCacheStatsSnapshot test_generic_cache_base() {
    using namespace reaction;

    class IntCache : public CacheBase<int, int> {
    public:
        IntCache(std::size_t maxSize, std::chrono::minutes ttl)
            : CacheBase(maxSize, ttl) {}

